//! Lower generated byte permutations through the selected backend.

use crate::convert::intrinsics::common::call_intrinsic;
use crate::{IntrinsicBackend, context};
use llvm_export::ops::{self as llvm, AsmKind, InlineAsmOpExt};
use llvm_export::types as llvm_types;
use pliron::builtin::types::{IntegerType, Signedness};
use pliron::context::{Context, Ptr};
use pliron::irbuild::dialect_conversion::DialectConversionRewriter;
use pliron::irbuild::inserter::Inserter;
use pliron::irbuild::rewriter::Rewriter;
use pliron::op::Op;
use pliron::operation::Operation;
use pliron::result::Result;

/// Lower one generated `prmt` mode.
pub(crate) fn convert_generated_prmt(
    ctx: &mut Context,
    rewriter: &mut DialectConversionRewriter,
    op: Ptr<Operation>,
    typed_intrinsic_name: &str,
    inline_ptx: &str,
) -> Result<()> {
    let operands: Vec<_> = op.deref(ctx).operands().collect();
    if !matches!(operands.len(), 2 | 3) || op.deref(ctx).get_num_results() != 1 {
        return pliron::input_err_noloc!(
            "generated prmt requires two or three operands and one result"
        );
    }
    let i32_ty = IntegerType::get(ctx, 32, Signedness::Signless);
    match context::lowering_options(ctx).intrinsic_backend {
        IntrinsicBackend::LlvmNvptx => {
            let argument_types = vec![i32_ty.into(); operands.len()];
            let function_ty = llvm_types::FuncType::get(ctx, i32_ty.into(), argument_types, false);
            let call = call_intrinsic(
                ctx,
                rewriter,
                op,
                typed_intrinsic_name,
                function_ty,
                operands,
            )?;
            rewriter.replace_operation(ctx, op, call);
            Ok(())
        }
        IntrinsicBackend::LibNvvm => {
            let constraints = if operands.len() == 3 {
                "=r,r,r,r"
            } else {
                "=r,r,r"
            };
            let inline_asm = llvm::InlineAsmOp::build(
                ctx,
                i32_ty.into(),
                operands,
                inline_ptx,
                constraints,
                AsmKind::Pure,
            );
            let asm_op = inline_asm.get_operation();
            rewriter.insert_operation(ctx, asm_op);
            rewriter.replace_operation(ctx, op, asm_op);
            Ok(())
        }
    }
}
